import { Box, Flex } from '@chakra-ui/react';
import { useTranslation } from 'react-i18next';
import { DOCUMENTS_BY_CATEGORY } from '@domain/accountDocument';
import { useGetAccountDocuments } from '@state/accountDocuments';
import { useGetAccount } from '@state/accounts';
import { VerticalScrollContainer } from '@ui/components/Containers';
import { Loading } from '@ui/components/Loading';
import { SettingsContainer } from '@ui/components/Settings';
import { FileUpload } from '@ui/components/molecules/FileUploader/FileUpload';
import { Label, Meta } from '@ui/components/typography';
import { isTruthy } from '@utils/isTruthy';
import { snakeToCamel } from '@utils/snakeToCamel';

export const Documents = () => {
  const { accountDocuments } = useGetAccountDocuments();
  const { currentAccount } = useGetAccount();
  const { t } = useTranslation(['settings', 'organizationApplication']);

  if (!accountDocuments || !currentAccount) {
    return <Loading />;
  }

  // category should not be null, unless the account is still draft (which should result in them being directed to org app)
  const pertinentDocTypes = DOCUMENTS_BY_CATEGORY[currentAccount.category!];
  const pertinentDocs = pertinentDocTypes
    ?.map((docType) => accountDocuments?.find((d) => d.documentType === docType))
    .filter(isTruthy);

  return (
    <VerticalScrollContainer>
      <SettingsContainer description={undefined} heading={t('settings:documents.heading')}>
        {pertinentDocs?.map(({ documentType, file: { name, size, url }, id }) => {
          const i18nKey = snakeToCamel(documentType);
          return (
            <Flex direction="column" gap={1} key={id} w={{ base: 'unset', lg: '60%', md: '75%' }}>
              <Label variant="bold">
                {t(
                  `organizationApplication:documentation.${i18nKey}.heading` as Parameters<
                    typeof t
                  >[0]
                )}
              </Label>
              <Meta variant="regular">
                {t(
                  `organizationApplication:documentation.${i18nKey}.description` as Parameters<
                    typeof t
                  >[0]
                )}
              </Meta>
              <Box border="dashed 1px" borderColor="neutral.400" px={4} py={6} rounded={8}>
                <FileUpload
                  fileName={name}
                  previewPath={url}
                  progress={100}
                  size={size}
                  status="complete"
                  useAbsolutePreviewPath
                />
              </Box>
            </Flex>
          );
        })}
      </SettingsContainer>
    </VerticalScrollContainer>
  );
};
